<svelte:options tag="carousel-basic" />

<script>
    import { onMount } from "svelte";

    export let images = [];
    export let showbutton = false;

    export function SetImages(data) {
        if (Array.isArray(data)) {
            images = data;
        }
    }
    let slider;
    //设置当前显示的图片索引
    let currentIndex = 0;
    //设置轮播间隔时间，单位毫秒
    const interval = 6000;
    //设置定时器变量
    let timer;
    //设置轮播函数
    function slideShow() {
        //隐藏所有图片
        let slides = slider.getElementsByClassName("slide");
        if (slides.length === 0) {
            return;
        }

        for (let i = 0; i < slides.length; i++) {
            slides[i].style.display = "none";
        }
        //显示当前图片
        slides[currentIndex].style.display = "block";
        //更新当前图片索引，如果到达最后一张，就回到第一张
        currentIndex++;
        if (currentIndex == slides.length) {
            currentIndex = 0;
        }
    }
    //在组件挂载后调用轮播函数一次，并设置定时器
    onMount(() => {
        slideShow();
        timer = setInterval(slideShow, interval);
    });

    //定义小圆点点击事件处理函数
    function handleDotClick(event) {
        //清除定时器，防止与轮播冲突
        clearInterval(timer);
        //获取当前点击的小圆点的索引
        let index = event.target.getAttribute("data-index");
        //更新当前图片索引
        currentIndex = index;
        //调用轮播函数
        slideShow();
        //重新设置定时器
        timer = setInterval(slideShow, interval);
    }

    //定义上一张按钮点击事件处理函数
    function handlePrevClick() {
        //清除定时器，防止与轮播冲突
        clearInterval(timer);
        //切换到上一张图片，如果到达第一张，就回到最后一张
        currentIndex--;
        if (currentIndex == -1) {
            currentIndex = slider.getElementsByClassName("slide").length - 1;
        }
        slideShow();
        //重新设置定时器
        timer = setInterval(slideShow, interval);
    }

    //定义下一张按钮点击事件处理函数
    function handleNextClick() {
        //清除定时器，防止与轮播冲突
        clearInterval(timer);
        //切换到下一张图片，如果到达最后一张，就回到第一张
        currentIndex++;
        if (currentIndex == slider.getElementsByClassName("slide").length) {
            currentIndex = 0;
        }
        slideShow();
        //重新设置定时器
        timer = setInterval(slideShow, interval);
    }
</script>

<div class="flex flex-col w-full h-full">
    <div class="h-full w-full p-6 relative" id="slider" bind:this={slider}>
        <!--使用each块遍历images数组，动态创建img元素，每张图片的class为slide-->
        {#each images as image}
            <img
                class="slide object-cover w-full h-full"
                src={image.url}
                alt={image.description}
                style:max-width="100%"
                style:max-height="100%"
            />
        {/each}
        {#if showbutton}
            <div id="buttons">
                <!--使用箭头图标作为按钮，分别用id为prev和next，绑定点击事件-->
                <span id="prev" on:click={handlePrevClick}>&lt;</span>
                <span id="next" on:click={handleNextClick}>&gt;</span>
            </div>
        {/if}
        <div
            class="absolute right-0 h-full z-10 flex flex-col justify-center items-center"
        >
            <!--使用each块遍历images数组，动态创建span元素，每个span的class为dot，用index表示索引，绑定点击事件-->
            {#each images as image, index}
                <span
                    class="w-4 h-4 bg-[#bbb] rounded-full inline-block"
                    data-index={index}
                    on:click={handleDotClick}
                />
            {/each}
        </div>
    </div>
</div>

<style type="text/postcss">
    /*添加样式*/
    .slide {
        display: none;
        width: 100%;
        height: auto;
        transition: opacity 1s;
    }
    .active {
        background-color: #717171;
    }
    #buttons {
        position: absolute;
        top: 50%;
        width: 100%;
        display: flex;
        justify-content: space-between;
    }
    #prev,
    #next {
        color: black;
        font-weight: bold;
        font-size: 60px;
        cursor: pointer;
    }
</style>
